class Solution:
    def minSwaps(self, s):
        """
        :type s: str
        :rtype: int
        """
        balance = 0
        swaps = 0

        for ch in s:
            if ch == '[':
                balance += 1
            else:
                balance -= 1

            # Negative balance means more closing than opening
            if balance < 0:
                swaps += 1
                balance = 1  # One swap fixes two brackets

        return swaps
